class Solution {
    public String smallestNumber(String pattern) {
        int n = pattern.length();
        int[] num = new int[n + 1];
        for (int i = 0; i < n; i++) {
            if (pattern.charAt(i) == 'I') {
                num[i] = num[i + 1] + 1;
            } else {
                num[i] = num[i + 1] - 1;
            }
        }
        StringBuilder sb = new StringBuilder();
        for (int i = n; i >= 0; i--) {
            sb.append(num[i]);
        }
        return sb.reverse().toString();
    }
}
```

